transform_01_normalize_upn_script.sourceCode:
function generateUpn(firstName, lastName, corporateSuffix) {
    if (!firstName || !lastName) return null;

    // Remove special characters, convert to lowercase, and concatenate
    let cleanFirst = firstName.trim().toLowerCase().replace(/[^a-zA-Z0-9]/g, '');
    let cleanLast = lastName.trim().toLowerCase().replace(/[^a-zA-Z0-9]/g, '');

    return cleanFirst + '.' + cleanLast + '@' + corporateSuffix;
}

// Local VS Code unit testing verification baseline
let testUpn = generateUpn(' Arthur ', 'M.', 'enterprise.com');
console.log('Processed Local Target Output: ' + testUpn);

transform_02_lifecycle_state_resolver.sourceCode:
function resolveLifecycleState(terminationDateStr) {
    if (!terminationDateStr) return 'active';

    let terminationDate = new Date(terminationDateStr);
    let currentDate = new Date();

    // If current system date is past termination date, flag account for deprovisioning
    return (currentDate >= terminationDate) ? 'terminated' : 'active';
}
